import { AfterViewInit, Component, ElementRef, OnDestroy, inject, viewChild } from '@angular/core';
import { CommonModule } from '@angular/common';
import { MinimapComponent } from '../../components/minimap/minimap';
import { GameService } from '../../services/game/game';
import { CacheService } from '../../services/cache';
import { MouseService } from '../../services/mouse';
import { InfoComponent } from '../../components/info/info';
import { WeatherComponent } from '../../components/weather/weather';
import { DayService } from '../../services/day';
import { PropertiesService } from '../../services/properties';
import { HeaderComponent } from '../../components/dump/header/header';
import { ButtonComponent } from '../../components/dump/button/button';
import { AuthService } from '../../services/api/auth';
import { RouterLink } from '@angular/router';

@Component({
  selector: 'game-page',
  imports: [CommonModule, MinimapComponent, InfoComponent, WeatherComponent, HeaderComponent, ButtonComponent, RouterLink],
  standalone: true,
  templateUrl: './game.html',
})
export class GamePage implements AfterViewInit, OnDestroy {
  protected readonly mouseService = inject(MouseService);
  protected readonly gameService = inject(GameService);
  protected readonly authService = inject(AuthService);
  private readonly cacheService = inject(CacheService);
  private readonly dayService = inject(DayService);
  private readonly propertiesService = inject(PropertiesService);

  private readonly mainCanvasRef = viewChild.required<ElementRef<HTMLCanvasElement>>(`mainCanvas`);

  private readonly tickInterval: number;

  public constructor() {
    this.cacheService.preloadImages(() => {
      this.gameService.drawViewport(this.mainCanvasRef().nativeElement);
    });

    this.tickInterval = setInterval(() => {
      this.dayService.tick();
      this.gameService.drawViewport(this.mainCanvasRef().nativeElement);
    }, 1000);
  }

  public ngAfterViewInit() {
    this.resizeMainCanvas();
    window.addEventListener('resize', () => {
      this.resizeMainCanvas();
      this.gameService.drawViewport(this.mainCanvasRef().nativeElement);
    });
    this.gameService.regenerateMap(this.mainCanvasRef().nativeElement, this.propertiesService.seed());
  }

  public ngOnDestroy() {
    clearInterval(this.tickInterval);
  }

  private resizeMainCanvas() {
    const canvas = this.mainCanvasRef().nativeElement;
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
  }
}
